1	import Alpine from 'alpinejs';
2	import { db, auth } from './firebase';
3	import { collection, query, where, getDocs, addDoc, onSnapshot, doc, updateDoc, getDocFromServer } from 'firebase/firestore';
4	import { createUserWithEmailAndPassword, sendEmailVerification, onAuthStateChanged, signInWithEmailAndPassword } from 'firebase/auth';
5	
6	declare global {
7	  interface Window {
8	    Alpine: any;
9	  }
10	}
11	
12	// Make Alpine available globally
13	window.Alpine = Alpine;
14	
15	document.addEventListener('alpine:init', () => {
16	  Alpine.data('app', () => ({
17	    route: window.location.pathname,
18	    phoneNumber: '',
19	    
20	    // Onboarding State
21	    onboardingPostcode: '',
22	    scanState: 'idle', // 'idle' | 'searching' | 'revealed'
23	    scannedLeads: [],
24	    
25	    registerName: '',
26	    registerEmail: '',
27	    registerPassword: '',
28	    registerTrade: '',
29	    registerCompany: '',
30	    registerArea: '',
31	    calloutFee: 50,
32	    filterStrictness: 3,
33	    pulseSchedule: '3days',
34	    loginEmail: '',
35	    loginPassword: '',
36	    loginError: '',
37	    isLoggingIn: false,
38	    user: { uid: 'dev-user', email: 'dev@jobfilter.uk' },
39	    isAuthReady: true,
40	    isEmailVerified: true,
41	    verificationMessage: '',
42	    subscriptionStatus: 'active',
43	
44	    handleFirestoreError(error: any, operationType: string, path: string | null) {
45	      const errInfo = {
46	        error: error instanceof Error ? error.message : String(error),
47	        authInfo: {
48	          userId: auth.currentUser?.uid,
49	          email: auth.currentUser?.email,
50	          emailVerified: auth.currentUser?.emailVerified,
51	          isAnonymous: auth.currentUser?.isAnonymous,
52	          tenantId: auth.currentUser?.tenantId,
53	          providerInfo: auth.currentUser?.providerData.map(provider => ({
54	            providerId: provider.providerId,
55	            displayName: provider.displayName,
56	            email: provider.email,
57	            photoUrl: provider.photoURL
58	          })) || []
59	        },
60	        operationType,
61	        path
62	      };
63	      console.error('Firestore Error: ', JSON.stringify(errInfo));
64	      if (errInfo.error.includes('Missing or insufficient permissions')) {
65	          this.loginError = "Permission denied. Please ensure you are logged in and have an active subscription.";
66	      }
67	      throw new Error(JSON.stringify(errInfo));
68	    },
69	
70	    async refreshEmailStatus() {
71	        if (!auth.currentUser) return;
72	        console.log("[AUTH] Manually refreshing user status...");
73	        try {
74	            await auth.currentUser.reload();
75	            this.user = auth.currentUser;
76	            this.isEmailVerified = auth.currentUser.emailVerified;
77	            if (this.isEmailVerified) {
78	                this.verificationMessage = "Success! Your email is verified.";
79	                this.checkSubscription();
80	            } else {
81	                this.verificationMessage = "Still waiting... make sure you clicked the link in your email.";
82	            }
83	        } catch (err: any) {
84	            console.error("[AUTH] Reload error:", err);
85	            this.verificationMessage = "Error checking status. Please try again.";
86	        }
87	    },
88	
89	    async resendVerification() {
90	        if (!auth.currentUser) return;
91	        console.log("[AUTH] Resending verification email...");
92	        try {
93	            await sendEmailVerification(auth.currentUser);
94	            this.verificationMessage = "Verification email resent! Check your inbox.";
95	        } catch (err: any) {
96	            console.error("[AUTH] Resend error:", err);
97	            this.verificationMessage = "Too many attempts. Please wait a few minutes.";
98	        }
99	    },
100	    
101	    // Vault State
102	    newVaultIdea: '',
103	    newVaultPhase: 3,
104	    vaultIdeas: [],
105	
106	    // Simulator State
107	    simState: 1,
108	    simMessages: [],
109	    isSimTyping: false,
110	    simInput: '',
111	    simFilterStrength: 3,
112	    
113	    // Dashboard variables
114	    activeTab: 'overview', // 'overview' | 'leads' | 'jobs' | 'safety' | 'business'
115	    showModal: null,
116	    tab: 'money',
117	    detailLead: null,
118	    showQuote: false,
119	    quoteTarget: null,
120	    quoteText: '',
121	    quoteGenerating: false,
122	    toastMsg: '',
123	    toastShow: false,
124	    dispatcherOn: true,
125	    receiptProcessing: false,
126	    receipts: [
127	      {id:1, merchant:'Screwfix — Tools & Fixings', date:'12 Apr 2025', cat:'Tools', amount:'142.80', vat:'23.80'},
128	      {id:2, merchant:'Shell Garage, Carlisle', date:'11 Apr 2025', cat:'Fuel', amount:'89.40', vat:'14.90'},
129	      {id:3, merchant:'Travis Perkins, CA1', date:'10 Apr 2025', cat:'Materials', amount:'314.20', vat:'52.37'}
130	    ],
131	    get receiptTotal() { return this.receipts.reduce((s: number,r: any) => s + parseFloat(r.amount), 0).toFixed(2); },
132	    get receiptVAT() { return this.receipts.reduce((s: number,r: any) => s + parseFloat(r.vat), 0).toFixed(2); },
133	    quotes: 6,
134	    miles: 30,
135	    get annualDebt() {
136	        return Math.round((this.quotes * 1.5 * 45 + this.miles * 0.20) * 52);
137	    },
138	    get savings() {
139	        return Math.round(this.annualDebt * 0.85);
140	    },
141	    leads: [],
142	    jobs: [],
143	    isLoadingLeads: false,
144	    selectedLead: null,
145	    isLeadModalOpen: false,
146	    unsubscribeLeads: null,
147	    
148	    // Trade Tools State
149	    selectedTradeTool: null,
150	    
151	    // Workshop & AI Receptionist State
152	    aiPersonality: 'professional',
153	    aiGreeting: 'Hi, thanks for contacting [Company]. To give you an accurate quote, I need a few details first.',
154	    aiAutoReply: true,
155	    workshopTools: [
156	      { id: 'quote', name: 'Instant Quote Gen', icon: '📄', desc: 'Generate professional PDF quotes in seconds.' },
157	      { id: 'invoice', name: 'Smart Invoicing', icon: '💰', desc: 'Send invoices that get paid faster.' },
158	      { id: 'schedule', name: 'AI Scheduler', icon: '📅', desc: 'Let customers book into your free slots.' }
159	    ],
160	
161	    // Brand Hub State
162	    brandColor: '#facc15',
163	    brandBio: 'Professional tradesperson serving the local area. Quality guaranteed.',
164	    brandReviews: [
165	      { author: 'John D.', rating: 5, text: 'Great service, very professional.' },
166	      { author: 'Sarah M.', rating: 5, text: 'Highly recommend for any plumbing work.' }
167	    ],
168	    
169	    async checkSubscription() {
170	        if (!this.user) return;
171	        console.log("[STRIPE EXTENSION] Checking subscription status...");
172	        const path = `customers/${this.user.uid}/subscriptions`;
173	        // The Stripe extension stores subscriptions in /customers/{uid}/subscriptions
174	        const subRef = collection(db, 'customers', this.user.uid, 'subscriptions');
175	        const q = query(subRef, where('status', 'in', ['active', 'trialing']));
176	        
177	        try {
178	            const snap = await getDocs(q);
179	            if (!snap.empty) {
180	                this.subscriptionStatus = 'active';
181	                console.log("[STRIPE EXTENSION] Active subscription found.");
182	                if (this.route === '/activation-pending') {
183	                    this.navigate('/dashboard');
184	                }
185	            } else {
186	                this.subscriptionStatus = 'none';
187	                console.log("[STRIPE EXTENSION] No active subscription.");
188	            }
189	        } catch (err) {
190	            this.handleFirestoreError(err, 'list', path);
191	            this.subscriptionStatus = 'none';
192	        }
193	    },
194	    
195	    get moneyLeads() {
196	        return this.leads.filter((l: any) => l.status === 'qualified' && !l.completed);
197	    },
198	
199	    get safetyLeads() {
200	        return this.leads.filter((l: any) => l.status === 'archived');
201	    },
202	
203	    openDetail(lead: any) { this.detailLead = lead; },
204	    closeDetail() { this.detailLead = null; },
205	    completeLead(id: any) {
206	      const l = this.leads.find((x: any) => x.id === id);
207	      if(l) { l.completed = true; this.closeDetail(); this.toast('✓ Job marked complete. Brand Hub updating...'); }
208	    },
209	    toast(msg: string) { this.toastMsg = msg; this.toastShow = true; setTimeout(() => this.toastShow = false, 3500); },
210	    genQuote(lead: any) {
211	      this.quoteTarget = lead; this.showQuote = true; this.quoteGenerating = true; this.quoteText = '';
212	      const lines = ['QUOTE REF: JF-2025-'+Math.floor(Math.random()*9000+1000)+'\n','Date: '+new Date().toLocaleDateString('en-GB')+'\n\n','To Whom It May Concern,\n\n','Thank you for your enquiry via JobFilter. Please find below our quote.\n\n','SCOPE OF WORKS\n','──────────────────────────────────\n',lead.summary+'\n\n','PRICING BREAKDOWN\n','──────────────────────────────────\n','Materials (estimated):    '+lead.budget+'\n','Labour:                   Included\n','Site protection & cleanup: Included\n\n','TOTAL (incl. VAT):        '+lead.budget+'\n\n','INCLUSIONS\n','──────────────────────────────────\n','✓ Full clean-up on completion\n','✓ 12-month workmanship guarantee\n','✓ Gas Safe / NICEIC certified work\n','✓ All waste disposal included\n\n','Valid for 14 days. To accept, reply YES.\n\n','Kind regards,\nScott — SR Trades, Carlisle\nwww.jobfilter.uk/sr-trades'];
213	      let i=0; const iv=setInterval(()=>{if(i<lines.length){this.quoteText+=lines[i++];}else{clearInterval(iv);this.quoteGenerating=false;}},55);
214	    },
215	    logReceipt() {
216	      this.receiptProcessing = true;
217	      setTimeout(() => {
218	        const merchants = ['Toolstation','Wickes','Jewson','HSS Hire','Dulux Decorator'];
219	        const cats = ['Tools','Materials','Hire','Paint','Fixings'];
220	        const idx = Math.floor(Math.random()*5);
221	        const amt = (Math.random()*200+20).toFixed(2);
222	        const vat = (parseFloat(amt)/6).toFixed(2);
223	        this.receipts.unshift({id:Date.now(),merchant:merchants[idx]+', Carlisle',date:new Date().toLocaleDateString('en-GB'),cat:cats[idx],amount:amt,vat:vat});
224	        this.receiptProcessing = false;
225	        this.toast('✓ Receipt scanned. Merchant, VAT and total extracted.');
226	      }, 2000);
227	    },
228	
229	    async init() {
230	      window.addEventListener('popstate', () => {
231	        this.route = window.location.pathname;
232	        this.handleRouteLogic();
233	      });
234	      
235	      // Test Firestore Connection
236	      try {
237	          console.log("[FIREBASE] Testing connection...");
238	          await getDocFromServer(doc(db, '_connection_test_', 'ping'));
239	          console.log("[FIREBASE] Connection successful.");
240	      } catch (error: any) {
241	          if (error.message && error.message.includes('the client is offline')) {
242	              console.error("[FIREBASE] CRITICAL: Client is offline. Check your Firebase configuration.");
243	              this.loginError = "Database is offline. Please check your internet or Firebase setup.";
244	          } else {
245	              // Ignore other errors (like document not found) as they still mean we're connected
246	              console.log("[FIREBASE] Connection test completed (doc might not exist, but we are online).");
247	          }
248	      }
249	
250	      onAuthStateChanged(auth, (user) => {
251	        // LOCK REMOVED: Preserving dev user if no real user is found
252	        if (user) {
253	            this.user = user;
254	            this.isEmailVerified = user.emailVerified;
255	            this.checkSubscription();
256	        } else {
257	            console.log("[AUTH] No user found, staying in DEV MODE");
258	        }
259	        this.isAuthReady = true;
260	        this.handleRouteLogic();
261	      });
262	
263	      // Auto-refresh email status when user returns to the tab
264	      window.addEventListener('focus', () => {
265	          if (this.route === '/activation-pending' && this.user && !this.isEmailVerified) {
266	              this.refreshEmailStatus();
267	          }
268	      });
269	
270	      // Removed synchronous this.handleRouteLogic() to prevent querying before auth resolves
271	    },
272	
273	    handleRouteLogic() {
274	      if (!this.isAuthReady) return; // Prevent logic before auth state is confirmed
275	
276	      // LOCK REMOVED: Bypassing auth and verification redirects
277	      
278	      if (this.route === '/dashboard') {
279	        this.subscribeLeads();
280	        this.subscribeJobs();
281	      } else {
282	        this.unsubscribeLeadsListener();
283	      }
284	
285	      if (this.route === '/blueprint') {
286	        this.fetchBlueprintIdeas();
287	      }
288	
289	      if (this.route === '/onboarding') {
290	        this.initSimulator();
291	      }
292	
293	      if (this.route === '/intake') {
294	        console.log("[INTAKE] Engine page loaded.");
295	      }
296	
297	      if (this.route === '/trade-tools') {
298	        console.log("[TRADE TOOLS] Page loaded.");
299	      }
300	    },
301	    
302	    navigate(path: string) {
303	      window.history.pushState({}, '', path);
304	      this.route = path;
305	      window.scrollTo(0, 0);
306	      
307	      // Reset scan state when navigating to onboarding
308	      if (path === '/onboarding') {
309	        this.scanState = 'idle';
310	        this.onboardingPostcode = '';
311	        this.scannedLeads = [];
312	      }
313	      
314	      this.handleRouteLogic();
315	    },
316	
317	    startScan() {
318	      if (!this.onboardingPostcode) return;
319	      this.scanState = 'searching';
320	      setTimeout(() => {
321	        this.scannedLeads = [
322	          { id: 1, title: 'Single Storey Extension', addressSnippet: 'Walmley Road, Solihull', trade: 'GENERAL', value: '45,000' },
323	          { id: 2, title: 'Dormer Loft Conversion', addressSnippet: 'Hagley Road, Edgbaston', trade: 'ROOFER', value: '38,000' },
324	          { id: 3, title: 'Full Refurbishment', addressSnippet: 'Lichfield Road, Sutton Coldfield', trade: 'GENERAL', value: '110,000' }
325	        ];
326	        this.scanState = 'revealed';
327	      }, 3000);
328	    },
329	
330	    unsubscribeLeadsListener() {
331	        if (this.unsubscribeLeads) {
332	            this.unsubscribeLeads();
333	            this.unsubscribeLeads = null;
334	        }
335	    },
336	    
337	    subscribeLeads() {
338	      this.isLoadingLeads = true;
339	      if (!auth.currentUser) {
340	          console.log("[DEV MODE] No authenticated user. Injecting mock leads instead of querying Firestore.");
341	          this.leads = [
342	              { id: 'mock1', customerName: 'John Smith', postcode: 'B14 7QH', description: 'Requires full house rewire. Has budget ready.', budget: '£3,500', status: 'qualified', createdAt: new Date().toISOString() },
343	              { id: 'mock2', customerName: 'Sarah Jenkins', postcode: 'B13 8DD', description: 'Emergency boiler replacement. No heating currently.', budget: '£2,200', status: 'qualified', createdAt: new Date().toISOString() }
344	          ];
345	          this.isLoadingLeads = false;
346	          return;
347	      }
348	      try {
349	        const leadsRef = collection(db, 'leads');
350	        this.unsubscribeLeads = onSnapshot(leadsRef, (snapshot) => {
351	            this.leads = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
352	            this.isLoadingLeads = false;
353	        }, (error) => {
354	            this.handleFirestoreError(error, 'list', 'leads');
355	            this.isLoadingLeads = false;
356	        });
357	      } catch (err) {
358	        console.error("Failed to setup leads listener:", err);
359	        this.isLoadingLeads = false;
360	      }
361	    },
362	
363	    async fetchBlueprintIdeas() {
364	      try {
365	        const res = await fetch('/api/blueprint');
366	        if (res.ok) {
367	          this.vaultIdeas = await res.json();
368	        }
369	      } catch (err) {
370	        console.error("Failed to fetch blueprint ideas:", err);
371	      }
372	    },
373	
374	    async addVaultIdea() {
375	        if (!this.newVaultIdea || !this.newVaultIdea.trim()) return;
376	        try {
377	            const res = await fetch('/api/blueprint', {
378	                method: 'POST',
379	                headers: { 'Content-Type': 'application/json' },
380	                body: JSON.stringify({
381	                    text: this.newVaultIdea,
382	                    phase: Number(this.newVaultPhase) || 3
383	                })
384	            });
385	            
386	            if (res.ok) {
387	                const newIdea = await res.json();
388	                // Optimistic UI update - create new array for guaranteed Alpine reactivity
389	                this.vaultIdeas = [newIdea, ...this.vaultIdeas];
390	                this.newVaultIdea = '';
391	                this.newVaultPhase = 3;
392	            } else {
393	                console.error("Server returned error:", await res.text());
394	            }
395	        } catch (err) {
396	            console.error("Failed to add idea:", err);
397	        }
398	    },
399	
400	    async deleteVaultIdea(id: any) {
401	        // Optimistic UI update
402	        const previousIdeas = [...this.vaultIdeas];
403	        this.vaultIdeas = this.vaultIdeas.filter((idea: any) => idea.id !== id);
404	        
405	        try {
406	            const res = await fetch(`/api/blueprint/${id}`, {
407	                method: 'DELETE'
408	            });
409	            if (!res.ok) {
410	                // Revert on failure
411	                this.vaultIdeas = previousIdeas;
412	                console.error("Failed to delete idea on server");
413	            }
414	        } catch (err) {
415	            this.vaultIdeas = previousIdeas;
416	            console.error("Failed to delete idea:", err);
417	        }
418	    },
419	
420	    openLead(lead: any) {
421	        this.selectedLead = lead;
422	        this.isLeadModalOpen = true;
423	    },
424	
425	    closeLead() {
426	        this.isLeadModalOpen = false;
427	        setTimeout(() => { this.selectedLead = null; }, 300);
428	    },
429	
430	    async convertLeadToJob(lead: any) {
431	        if (!lead) return;
432	        console.log("[JOBS] Converting lead to job:", lead.id);
433	        try {
434	            const jobsRef = collection(db, 'jobs');
435	            await addDoc(jobsRef, {
436	                leadId: lead.id,
437	                customerName: lead.customerName,
438	                customerPhone: lead.customerPhone,
439	                customerAddress: lead.customerAddress || 'No address provided',
440	                trade: lead.trade,
441	                budget: lead.budget,
442	                description: lead.description,
443	                status: 'pending',
444	                createdAt: new Date().toISOString(),
445	                uid: this.user.uid
446	            });
447	            
448	            // Mark lead as converted
449	            const leadRef = doc(db, 'leads', lead.id);
450	            await updateDoc(leadRef, {
451	                status: 'converted'
452	            });
453	            
454	            this.closeLead();
455	            alert("Job created! View it in the Jobs tab.");
456	        } catch (err) {
457	            console.error("[JOBS] Conversion error:", err);
458	            alert("Failed to create job. Please try again.");
459	        }
460	    },
461	
462	    subscribeJobs() {
463	        if (!auth.currentUser) {
464	            console.log("[DEV MODE] No authenticated user. Injecting mock jobs instead of querying Firestore.");
465	            this.jobs = [
466	                { id: 'job-mock1', customerName: 'John Smith', customerPhone: '07700 900123', status: 'pending', budget: '£3,500', description: 'Full house rewire.' }
467	            ];
468	            return;
469	        }
470	        if (!this.user) return;
471	        console.log("[JOBS] Subscribing to jobs...");
472	        const jobsRef = collection(db, 'jobs');
473	        const q = query(jobsRef, where('uid', '==', this.user.uid));
474	        onSnapshot(q, (snapshot) => {
475	            this.jobs = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
476	        }, (err) => {
477	            this.handleFirestoreError(err, 'list', 'jobs');
478	        });
479	    },
480	
481	    async reclaimLead(leadId: string) {
482	        try {
483	            const leadRef = doc(db, 'leads', leadId);
484	            await updateDoc(leadRef, {
485	                status: 'qualified',
486	                reclaimedAt: new Date().toISOString()
487	            });
488	        } catch (err) {
489	            console.error("Failed to reclaim lead:", err);
490	        }
491	    },
492	
493	    async simulateLead() {
494	        try {
495	            const leadsRef = collection(db, 'leads');
496	            const randomId = Math.floor(Math.random() * 9000) + 1000;
497	            const isQualified = Math.random() > 0.3; // 70% chance of being qualified
498	            
499	            const projects = [
500	                { type: 'Extension', desc: 'Large wrap-around kitchen extension with bi-fold doors.', size: 'large' },
501	                { type: 'Loft Conversion', desc: 'Dormer loft conversion for a new master bedroom.', size: 'large' },
502	                { type: 'New Build', desc: 'Single detached 3-bed dwelling on private plot.', size: 'large' },
503	                { type: 'Refurbishment', desc: 'Full house refurbishment including new kitchen and bathroom.', size: 'medium' },
504	                { type: 'Repair', desc: 'Small electrical repair and socket replacement.', size: 'small' },
505	                { type: 'Maintenance', desc: 'Gutter cleaning and minor roof tile replacement.', size: 'small' }
506	            ];
507	            
508	            const project = projects[Math.floor(Math.random() * projects.length)];
509	            const tier = (project.size === 'large') ? 'HAMMER' : 'SCOUT';
510	            const price = tier === 'HAMMER' ? '£60' : '£30';
511	            
512	            const areas = ['Birmingham', 'Solihull', 'Sutton Coldfield', 'Dudley', 'Walsall'];
513	            const area = areas[Math.floor(Math.random() * areas.length)];
514	            
515	            let hammerHook = '';
516	            if (tier === 'HAMMER') {
517	                hammerHook = `I saw the approved plans for your new ${project.desc.toLowerCase()} in ${area} and would love to discuss the build with you.`;
518	            }
519	
520	            await addDoc(leadsRef, {
521	                lead_id: `JF-${randomId}`,
522	                customerName: `Customer ${randomId}`,
523	                jobDescription: isQualified ? project.desc : 'Need some work done, not sure what exactly.',
524	                postcode: isQualified ? 'B14 7TE' : '',
525	                budget: isQualified ? (project.size === 'large' ? '45000' : '1500') : '',
526	                status: isQualified ? 'qualified' : 'archived',
527	                tier: isQualified ? tier : null,
528	                price: isQualified ? price : null,
529	                hammer_hook: hammerHook,
530	                area: area,
531	                project_type: project.type,
532	                createdAt: new Date().toISOString(),
533	                uid: this.user?.uid || 'dev-user'
534	            });
535	        } catch (err: any) {
536	            console.error("Failed to simulate lead. Error details:", {
537	                message: err.message,
538	                code: err.code,
539	                path: 'leads',
540	                user: this.user?.uid
541	            });
542	        }
543	    },
544	
545	    // Simulator Logic
546	    initSimulator() {
547	        this.simState = 1;
548	        this.simMessages = [
549	            { sender: 'bot', text: "Hi, I'm the automated assistant for this business. To get you a quote faster, I need a few details." }
550	        ];
551	    },
552	
553	    async sendSimMessage(text: string) {
554	        if (!text || !text.trim()) return;
555	        
556	        const userMsg = text;
557	        this.simMessages.push({ sender: 'user', text: userMsg });
558	        this.isSimTyping = true;
559	
560	        // Call our backend webhook to simulate the AI
561	        try {
562	            const res = await fetch('/api/whatsapp/webhook', {
563	                method: 'POST',
564	                headers: { 'Content-Type': 'application/json' },
565	                body: JSON.stringify({
566	                    message: userMsg,
567	                    tradie_id: 'sim_123',
