233	// ── Write My Quote ─────────────────────────────────────────────────────────────
234	const QUOTE_VARIANTS = [
235	  [
236	    `✓ Why I'm the right person: I specialise in this exact type of work and have completed dozens of similar jobs across your area.`,
237	    `✓ Experience: Years of hands-on experience means I get it right first time — no comebacks, no mess.`,
238	    `✓ Local trust: I'm local, fully insured, and my customers recommend me to their neighbours. References available.`,
239	  ],
