251	
252	function WriteMyQuote({ useFeature }: { useFeature: () => boolean }) {
253	  const [desc, setDesc] = useState('');
254	  const [bullets, setBullets] = useState<string[]>([]);
255	  const [variantIdx, setVariantIdx] = useState(0);
256	  const [copied, setCopied] = useState(false);
