258	  function generate() {
259	    if (!desc.trim()) return;
260	    if (!useFeature()) return;
261	    setVariantIdx(0);
262	    setBullets(QUOTE_VARIANTS[0]);
263	  }
264	
265	  function improve() {
266	    if (!useFeature()) return;
267	    const next = (variantIdx + 1) % QUOTE_VARIANTS.length;
268	    setVariantIdx(next);
269	    setBullets(QUOTE_VARIANTS[next]);
270	  }
271	
272	  function copy() {
273	    navigator.clipboard.writeText(bullets.join('\n'));
274	    setCopied(true);
275	    setTimeout(() => setCopied(false), 2000);
276	  }
277	
278	  return (
